(()=>{"use strict";self.addEventListener("push",t=>{console.log("SW: Push Event Received",t);let i=t.data?.json()??{};console.log("SW: Push Data Parsed:",i);let o=i.title||"Notifikasi Baru",n=i.url||i.data&&i.data.url||i.action_url||"/dashboard",e={body:i.body||"Anda mendapat pesan baru.",icon:i.icon||"/images/logo-mp.png",badge:"/badge.png",data:{url:n},vibrate:[100,50,100],actions:[{action:"open_url",title:"Buka Aplikasi"}]};t.waitUntil(self.registration.showNotification(o,e).then(()=>console.log("SW: Success showing notification")).catch(t=>console.error("SW: Error showing notification:",t)))}),self.addEventListener("notificationclick",t=>{t.notification.close();let i=t.notification.data.url||"/dashboard";t.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(t=>{for(let o of t)if(o.url===i&&"focus"in o)return o.focus();if(self.clients.openWindow)return self.clients.openWindow(i)}))})})();